dec_med = pow (0.9, 30/fps);;
dec_slow = pow (0.9, 30/fps);;
beat = max (max (bass, mid), treb);;
avg = avg*dec_slow + beat*(1-dec_slow);;
is_beat = ((beat) > (.1+avg+peak)) * ((time) > (t0+.2));;
t0 = is_beat*time + (1-is_beat)*t0;;
peak = is_beat * beat + (1-is_beat)*peak*dec_med;;
index = (index + is_beat) %16;;
index2 = (index2 + is_beat*bnot(index))%5;;
monitor = index2;;
q20 = avg;;
q21 = beat;;
q22 = peak;;
q23 = index;;
q24 = is_beat;;
q26 = bass + mid + treb;;
q27 = index;;
q28 = index2;;
k1 =  is_beat*((index%2) == (0));;
p1 =  k1*(p1+1) + (1-k1)*p1;;
p2 = dec_med * p2+ (1-dec_med)*p1;;
rott_ = p2 * 3.1416/4;;
rott =  rott +  .2*30/fps*q2;;
q1 = cos(rott);;
q2 = sin(rott);;
q3 = -q2;;
q4 = q1;;
ran = bnot(q24)*ran + q24 * (rand(50)-24);;
tran = tan(ran);;
tran = max(tran,-5);;
tran = min(tran,5);;
trel = trel + .02*30/fps*tran+q24;;
q5 = cos(trel);;
q6 = sin(trel);;
q7 = -q6;;
q8 = q5;;
movex = movex*dec_slow + .1*sin(rott)*30/fps;;
